#include<bits/stdc++.h>
using namespace std;
#define ui unsigned 
ui s;
inline ui get(ui x)
{
	x^=x<<13;
	x^=x>>17;
	x^=x<<5;
	return s=x; 
}
vector<int> mp[500010];
int d[500010],fa[500010][24],lg[500010];
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int main()
{
    int n,q;
    scanf("%d%d%u",&n,&q,&s);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    int lstans=0,root=0;
    for(int i=1;i<=n;i++)
    {
        int f;
        scanf("%d",&f);
        if(f!=0)
        {
            mp[f].push_back(i);
        }
        else
        {
            root=i;
        }
    }
    dfs(root);
    long long ans=0;
    for(int i=1;i<=q;i++)
    {
        int x=((get(s)^lstans)%n)+1;
        int k=(get(s)^lstans)%d[x];
        // printf("x=%d,k=%d\n",x,k);
        for(int i=0;i<=lg[d[x]];i++)
        {
            if(k&(1<<i))
            {
                x=fa[x][i];
            }
        }
        lstans=x;
        ans^=(1ll*i*x);
        // printf("%d\n",x);
    }
    printf("%lld",ans);
    return 0;
}
